const RELEASE="16.0";const KEY=`painel-da-mirna:architecture:${RELEASE}`;async function upgrade(){if(localStorage.getItem(KEY)==="done")return;try{if("serviceWorker"in navigator){const registrations=await navigator.serviceWorker.getRegistrations();await Promise.all(registrations.map(registration=>registration.unregister()));}if("caches"in window){const keys=await caches.keys();await Promise.all(keys.map(key=>caches.delete(key)));}localStorage.setItem(KEY,"done");location.replace(`/?release=${RELEASE}`);}catch{localStorage.setItem(KEY,"done");location.replace(`/?release=${RELEASE}`);}}upgrade();